const hardhatPlugin: HardhatPlugin = definePlugin({
  id: "builtin:console",
  tasks: [
    task("console", "Open a hardhat console")
      .addOption({
        name: "history",
        description: "Path to a history file",
        defaultValue: "console-history.txt",
      })
      .addFlag({
        name: "noCompile",
        description: "Do not compile the project before starting the console",
      })
      .addVariadicArgument({
        name: "commands",
        description: "Commands to run when the console starts",
        defaultValue: [],
      })
      .setAction(async () => await import("./task-action.js"))
      .build(),
  ],
  dependencies: () => [import("../solidity/index.js")],
  npmPackage: "hardhat",
});

extendEnvironment((hre) => {
    hre.starknetJs = new StarknetLegacyWrapper(hre.config.starknet.networkConfig);

    const venvPath = hre.config.starknet.venv;
    if (venvPath) {
        setVenvWrapper(hre, venvPath);
    } else {
        const repository = CAIRO_CLI_DOCKER_REPOSITORY;
        const tag = getCairoCliImageTagByArch(hre.config.starknet.dockerizedVersion);

        const image = { repository, tag };
        const cairoPaths = [];
        for (const cairoPath of hre.config.paths.cairoPaths || []) {
            cairoPaths.push(adaptPath(hre.config.paths.root, cairoPath));
        }

        hre.starknetWrapper = new DockerWrapper(image, hre.config.paths.root, cairoPaths, hre);

        const amarnaImage = { repository: AMARNA_DOCKER_REPOSITORY, tag: AMARNA_DOCKER_IMAGE_TAG };
        hre.amarnaDocker = new AmarnaDocker(
            amarnaImage,
            hre.config.paths.root,
            hre.config.paths.cairoPaths || [],
            hre
        );
    }
});

subtask(
    TASK_COMPILE_SOLIDITY_LOG_COMPILATION_RESULT,
    async ({ compilationJobs }: { compilationJobs: CompilationJob[] }, hre, _runSuper) => {
        if (hre.config.zksolc.settings.areLibrariesMissing) {
            console.info(chalk.yellow(MISSING_LIBRARIES_NOTICE));
            console.info(chalk.red(COMPILE_AND_DEPLOY_LIBRARIES_INSTRUCTIONS));
            console.info(chalk.yellow(MISSING_LIBRARY_LINK));
        } else {
            let count = 0;
            for (const job of compilationJobs) {
                count += job.getResolvedFiles().filter((file) => job.emitsArtifacts(file)).length;
            }

            if (count > 0) {
                console.info(chalk.green(`Successfully compiled ${count} Solidity ${pluralize(count, 'file')}`));
            }
        }
    },
);

if (SUPPORTED_L1_TESTNETS.includes(ethNetwork)) {
    ethWeb3Provider =
        ethNetwork in networks && isHttpNetworkConfig(networks[ethNetwork])
            ? new ethers.JsonRpcProvider((networks[ethNetwork] as HttpNetworkConfig).url)
            : ethers.getDefaultProvider(ethNetwork);
} else {
    if (ethNetwork === 'localhost' || ethNetwork === '') {
        ethWeb3Provider = _createDefaultEthProvider();
    } else if (isValidEthNetworkURL(ethNetwork)) {
        ethWeb3Provider = new ethers.JsonRpcProvider(ethNetwork);
    } else {
        ethWeb3Provider =
            ethNetwork in networks && isHttpNetworkConfig(networks[ethNetwork])
                ? new ethers.JsonRpcProvider((networks[ethNetwork] as HttpNetworkConfig).url)
                : ethers.getDefaultProvider(ethNetwork);
    }
}

const singleVersionBuildProfileUserConfigType = conditionalUnionType(
  [
    [
      (data) =>
        isObject(data) &&
        (!("type" in data) || data.type === undefined || data.type === "solc"),
      solcSolidityCompilerUserConfigType.extend({
        isolated: z.boolean().optional(),
        toolVersionsInBuildInfo: z.boolean().optional(),
        ...incompatibleVersionFields,
      }),
    ],
    [
      (data) => isObject(data) && "type" in data && data.type !== "solc",
      otherSolidityCompilerUserConfigType.extend({
        isolated: z.boolean().optional(),
        toolVersionsInBuildInfo: z.boolean().optional(),
        ...incompatibleVersionFields,
      }),
    ],
  ],
  "Expected a valid compiler configuration",
);

