    getSigners: () => Promise<HardhatZksyncSigner[]>;
    getSigner(address: string): Promise<HardhatZksyncSigner>;
    getWallets: () => Promise<Wallet[]>;
    getWallet: (privateKeyOrIndex?: string | number) => Promise<Wallet>;
    getContractFactory: typeof getContractFactory;
    getContractAt: typeof getContractAt;
    getImpersonatedSigner: (address: string) => Promise<HardhatZksyncSigner>;
    extractFactoryDeps: (artifact: ZkSyncArtifact) => Promise<string[]>;
    loadArtifact: (name: string) => Promise<ZkSyncArtifact>;
    deployContract: (
        artifact: ZkSyncArtifact | string,
        constructorArguments: any[],
        walletOrSigner?: HardhatZksyncSignerOrWalletOrFactoryOptions,
        deploymentType?: DeploymentType,
        overrides?: ethers.Overrides,
        additionalFactoryDeps?: ethers.BytesLike[],
    ) => Promise<Contract>;
}

class OverrideCompilerSolcUserConfigUpdater implements SolcUserConfigUpdater {
    public suituble(_solcUserConfig: SolcUserConfig[] | Map<string, SolcUserConfig>, _file?: string): boolean {
        return _solcUserConfig instanceof Map && _file !== undefined;
    }

    public update(
        _compiler: SolcConfig,
        _latestEraVersion: string,
        _zksolc: ZkSolcConfig,
        _userConfigCompilers: Map<string, SolcUserConfig>,
        _file: string,
    ): void {
        const compilerInfo = _userConfigCompilers.get(_file);

        if (compilerInfo?.eraVersion) {
            _compiler.eraVersion = compilerInfo.eraVersion;
            return;
        }

        if (isBreakableCompilerVersion(_zksolc.version)) {
            _compiler.eraVersion = _latestEraVersion;
        }
    }
}

class OverrideCompilerSolcUserConfigNormalizer implements SolcUserConfigNormalizer {
    public suituble(_solcUserConfig: SolcUserConfig[] | Map<string, SolcUserConfig>, _file?: string): boolean {
        return _solcUserConfig instanceof Map && _file !== undefined;
    }

    public normalize(
        _compiler: SolcConfig,
        _zkSolcConfig: any,
        _latestEraVersion: string,
        _userConfigCompilers: Map<string, SolcUserConfig>,
        _file: string,
    ): string {
        const compilerInfo = _userConfigCompilers.get(_file);

        if (isBreakableCompilerVersion(_zkSolcConfig.version)) {
            return compilerInfo?.eraVersion
                ? getZkVmNormalizedVersion(_compiler.version, compilerInfo.eraVersion)
                : getZkVmNormalizedVersion(_compiler.version, _latestEraVersion);
        }

        return compilerInfo?.eraVersion
            ? getZkVmNormalizedVersion(_compiler.version, compilerInfo.eraVersion)
            : _compiler.version;
    }
}

return function (this: Chai.AssertionStatic, ...args: any[]) {
  const [actualArg, message] = args;
  const expectedFlag = chaiUtils.flag(this, "object");

  if (message !== undefined) {
    chaiUtils.flag(this, "message", message);
  }

  const actual = tryGetAddressSync(actualArg);
  const expected = tryGetAddressSync(expectedFlag);
  if (
    functionName === "eq" &&
    expected !== undefined &&
    actual !== undefined
  ) {
    this.assert(
      expected === actual,
      `expected '${expected}' to ${readableName} '${actual}'.`,
      `expected '${expected}' to ${readableNegativeName} '${actual}'.`,
      actual.toString(),
      expected.toString(),
    );
  } else {
    _super.apply(this, args);
  }
};

if (kind === CallKind.Create) {
  openingLine = `[${gasUsed}] ${colorize("yellow", "→ new")} ${contract ?? "<unknown>"}@${address}`;
  // TODO: Uncomment this when the formattedInputs starts containing
  // the address of where the contract was deployed instead of the code.
  // if (formattedInputs !== undefined) {
  //   openingLine = `${openingLine}@${formattedInputs}`;
  // }
} else {
  openingLine = `[${gasUsed}] ${color(contract ?? address)}`;
  if (formattedInputs !== undefined) {
    openingLine = `${openingLine}::${formattedInputs}`;
  }
  if (value !== 0n) {
    openingLine = `${openingLine} {value: ${value}}`;
  }
  if (kind === CallKind.StaticCall) {
    openingLine = `${openingLine} ${colorize("yellow", "[staticcall]")}`;
  } else if (kind === CallKind.DelegateCall) {
    openingLine = `${openingLine} ${colorize("yellow", "[delegatecall]")}`;
  } else if (kind === CallKind.CallCode) {
    openingLine = `${openingLine} ${colorize("yellow", "[callcode]")}`;
  }
}

if (chainId == 31337) {
    const BASE_FEE = "100000000000000000"
    const GAS_PRICE_LINK = "1000000000" // 0.000000001 LINK per gas
    const WEI_PER_UNIT_LINK = "4000000000000000"

    const VRFCoordinatorV2MockFactory = await ethers.getContractFactory("VRFCoordinatorV2_5Mock")
    VRFCoordinatorV2Mock = await VRFCoordinatorV2MockFactory.deploy(BASE_FEE, GAS_PRICE_LINK, WEI_PER_UNIT_LINK)
    vrfCoordinatorAddress = VRFCoordinatorV2Mock.address

    const fundAmount = networkConfig[chainId]["fundAmount"] || "1000000000000000000"
    const transaction = await VRFCoordinatorV2Mock.createSubscription()
    const transactionReceipt = await transaction.wait(1)
    subscriptionId = ethers.BigNumber.from(transactionReceipt.events[0].topics[1])
    await VRFCoordinatorV2Mock.fundSubscription(subscriptionId, fundAmount)
} else {
    subscriptionId = networkConfig[chainId]["subscriptionId"]
    vrfCoordinatorAddress = networkConfig[chainId]["vrfCoordinator"]
}
